public boolean equalSumSubarrays(int[] nums) {
    Set<Integer> sums = new HashSet<>();
    for (int i = 1; i < nums.length; ++i) {
        int sum = nums[i] + nums[i - 1];
        if (sums.contains(sum)) return true;
        sums.add(sum);
    }
    return false;
}
```

